(7, 'Admin', 1, 'AllUsers', NULL, NULL, 'Campus WiFi Maintenance', 'Please note that the campus WiFi will undergo maintenance tonight from 10 PM to 12 AM. Connectivity may be interrupted.', NULL, NULL, '2025-11-20 09:30:00'),
(8, 'Admin', 1, 'AllTeachers', NULL, NULL, 'Staff Meeting Reminder', 'A general staff meeting will be held tomorrow at 10 AM in the conference hall. All teachers are requested to attend.', NULL, NULL, '2025-11-19 11:15:00'),
(9, 'Admin', 1, 'ClassStudents', NULL, 4, 'Internal Exam Schedule Updated', 'The updated internal exam schedule for Class 4 has been published. Students are advised to check their dashboard.', NULL, NULL, '2025-11-20 08:50:00'),
(10, 'Admin', 1, 'DepartmentUsers', 2, NULL, 'Lab Equipment Allocation', 'Department 2 students are informed that new lab equipment will be available for use from next week.', NULL, NULL, '2025-11-19 10:05:00'),
(11, 'Admin', 1, 'AllUsers', NULL, NULL, 'Holiday Announcement', 'The college will remain closed this Friday due to a declared public holiday. Classes will resume on Monday.', NULL, NULL, '2025-11-20 07:00:00'),
(12, 'Admin', 1, 'DepartmentTeachers', 3, NULL, 'Syllabus Submission Deadline', 'All teachers of Department 3 are requested to submit the completed syllabus reports by the end of this week.', NULL, NULL, '2025-11-19 14:20:00'),
(13, 'Admin', 1, 'ClassStudents', NULL, 6, 'Assignment Submission', 'Students of Class 6 must submit their pending assignments by 22 November. Late submissions will not be accepted.', NULL, NULL, '2025-11-20 12:10:00'),
(14, 'Admin', 1, 'DepartmentAll', 4, NULL, 'Workshop Registration Open', 'Registrations are now open for the upcoming web development workshop for Department 4. Limited seats available.', NULL, NULL, '2025-11-19 16:45:00'),
(15, 'Admin', 1, 'AllTeachers', NULL, NULL, 'Semester Evaluation Meeting', 'All teachers are requested to assemble for the semester performance evaluation meeting on 23 November at 2 PM.', NULL, NULL, '2025-11-20 15:30:00'),
(16, 'Admin', 1, 'AllUsers', NULL, NULL, 'Campus Cleanliness Drive', 'A campus-wide cleanliness drive will be conducted on 25 November. Volunteers are welcome to join.', NULL, NULL, '2025-11-19 09:10:00'),
